public void testIssue618_aliased_no_property() {
  this.removeGlobal = false;
  testSame(
      "function f() {\n" +
      "  var a = [], b;\n" +
      "  a.push(b = []);\n" +
      "  return a;\n" +
      "}");
}

public void testIssue618_literal_with_property() {
  this.removeGlobal = false;
  test(
      "function f() {\n" +
      "  var b = [];\n" +
      "  b[0] = 1;\n" +
      "  return 42;\n" +
      "}",
      "function f() {\n" +
      "  return 42;\n" +
      "}");
}

public void testIssue618_non_literal_no_alias() {
  this.removeGlobal = false;
  test(
      "function f(x) {\n" +
      "  var b = x;\n" +
      "  return 42;\n" +
      "}",
      "function f(x) {\n" +
      "  return 42;\n" +
      "}");
}
